{"signature":"0x455cb4d578dff7d6163c49a8c28a8a76ae90fff859ee534c37af9fab136255414fc7157fdb52aadbaa5c59b130b60101f73045a0b095731493a1dff7fd9deab31c","funding_sources_and_total_prior_funding_usd":"$6,000 from GitCoin Rounds and Hackathon wins","team_size":"6","team_profiles":"@vmkirin
 @katiecherry02
 @reedtaisiya
 @erinmagennis
